  1→/**
  2→ * Orchestrator HTTP route handlers.
  3→ *
  4→ * Pure request->response mappings that delegate to session-lifecycle functions
  5→ * injected via OrchestratorRouteDeps. No direct DB or IO access.
  6→ */
  7→import { jsonError, jsonResponse } from "../http/response";
  8→import { withRequestLogging, type RouteHandler } from "../http/request-logging";
  9→import type {
 10→  OrchestratorSessionResult,
 11→  SessionStatusResult,
 12→  AbortSessionResult,
 13→  AcceptSessionResult,
 14→  ReviewResult,
 15→  RejectSessionResult,
 16→  PromptSessionResult,
 17→} from "./session-lifecycle";
 18→import type { SseRegistry } from "../streaming/sse-registry";
 19→
 20→// ---------------------------------------------------------------------------
 21→// Port: Dependencies as function signatures
 22→// ---------------------------------------------------------------------------
 23→
 24→export type OrchestratorRouteDeps = {
 25→  createSession: (
 26→    workspaceId: string,
 27→    taskId: string,
 28→    authToken: string,
 29→  ) => Promise<OrchestratorSessionResult>;
 30→  getSessionStatus: (sessionId: string) => Promise<SessionStatusResult>;
 31→  abortSession: (sessionId: string) => Promise<AbortSessionResult>;
 32→  acceptSession: (
 33→    sessionId: string,
 34→    summary: string,
 35→  ) => Promise<AcceptSessionResult>;
 36→  getReview: (sessionId: string) => Promise<ReviewResult>;
 37→  rejectSession: (
 38→    sessionId: string,
 39→    feedback: string,
 40→  ) => Promise<RejectSessionResult>;
 41→  sendPrompt: (
 42→    sessionId: string,
 43→    text: string,
 44→  ) => Promise<PromptSessionResult>;
 45→};
 46→
 47→// ---------------------------------------------------------------------------
 48→// Request body parsing
 49→// ---------------------------------------------------------------------------
 50→
 51→type AssignBody = { taskId?: string };
 52→type AcceptBody = { summary?: string };
 53→type RejectBody = { feedback?: string };
 54→type PromptBody = { text?: string };
 55→
 56→async function parseJsonBody<T>(request: Request): Promise<T | undefined> {
 57→  try {
 58→    return (await request.json()) as T;
 59→  } catch {
 60→    return undefined;
 61→  }
 62→}
 63→
 64→function extractAuthToken(request: Request): string {
 65→  return request.headers.get("Cookie") ?? "";
 66→}
 67→
 68→// ---------------------------------------------------------------------------
 69→// Response builders (pure)
 70→// ---------------------------------------------------------------------------
 71→
 72→function assignResponse(
 73→  workspaceId: string,
 74→  value: { agentSessionId: string; streamId: string; worktreeBranch: string },
 75→): Response {
 76→  return jsonResponse(
 77→    {
 78→      agentSessionId: value.agentSessionId,
 79→      streamId: value.streamId,
 80→      streamUrl: `/api/orchestrator/${workspaceId}/sessions/${value.agentSessionId}/stream`,
 81→    },
 82→    200,
 83→  );
 84→}
 85→
 86→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
 87→  const result: Record<string, unknown> = {};
 88→  for (const [key, value] of Object.entries(obj)) {
 89→    if (value !== undefined) {
 90→      result[key] = value;
 91→    }
 92→  }
 93→  return result as Partial<T>;
 94→}
 95→
 96→function statusResponse(
 97→  sessionId: string,
 98→  value: {
 99→    orchestratorStatus: string;
100→    worktreeBranch?: string;
101→    worktreePath?: string;
102→    startedAt?: string;
103→    lastEventAt?: string;
104→    error?: string;
105→  },
106→): Response {
107→  return jsonResponse(
108→    {
109→      agentSessionId: sessionId,
110→      orchestratorStatus: value.orchestratorStatus,
111→      ...pickDefined({
112→        worktreeBranch: value.worktreeBranch,
113→        worktreePath: value.worktreePath,
114→        startedAt: value.startedAt,
115→        lastEventAt: value.lastEventAt,
116→        error: value.error,
117→      }),
118→    },
119→    200,
120→  );
121→}
122→
123→function acceptResponse(): Response {
124→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
125→}
126→
127→function abortResponse(): Response {
128→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
129→}
130→
131→function reviewResponse(value: {
132→  taskTitle: string;
133→  diff: unknown;
134→  session: unknown;
135→}): Response {
136→  return jsonResponse(value, 200);
137→}
138→
139→function rejectResponse(): Response {
140→  return jsonResponse({ rejected: true, continuing: true }, 200);
141→}
142→
143→function promptResponse(): Response {
144→  return jsonResponse({ delivered: true }, 202);
145→}
146→
147→function sessionErrorResponse(error: {
148→  message: string;
149→  httpStatus: number;
150→}): Response {
151→  return jsonError(error.message, error.httpStatus);
152→}
153→
154→// ---------------------------------------------------------------------------
155→// Route handler factory
156→// ---------------------------------------------------------------------------
157→
158→export function createOrchestratorRouteHandlers(deps: OrchestratorRouteDeps) {
159→  const assign: RouteHandler = async (request) => {
160→    const workspaceId = request.params.workspaceId;
161→    const body = await parseJsonBody<AssignBody>(request);
162→
163→    if (!body?.taskId) {
164→      return jsonError("taskId is required", 400);
165→    }
166→
167→    const authToken = extractAuthToken(request);
168→    const result = await deps.createSession(workspaceId, body.taskId, authToken);
169→
170→    if (!result.ok) {
171→      return sessionErrorResponse(result.error);
172→    }
173→
174→    return assignResponse(workspaceId, result.value);
175→  };
176→
177→  const status: RouteHandler = async (request) => {
178→    const sessionId = request.params.sessionId;
179→    const result = await deps.getSessionStatus(sessionId);
180→
181→    if (!result.ok) {
182→      return sessionErrorResponse(result.error);
183→    }
184→
185→    return statusResponse(sessionId, result.value);
186→  };
187→
188→  const accept: RouteHandler = async (request) => {
189→    const sessionId = request.params.sessionId;
190→    const body = await parseJsonBody<AcceptBody>(request);
191→    const summary = body?.summary ?? "";
192→
193→    const result = await deps.acceptSession(sessionId, summary);
194→
195→    if (!result.ok) {
196→      return sessionErrorResponse(result.error);
197→    }
198→
199→    return acceptResponse();
200→  };
201→
202→  const abort: RouteHandler = async (request) => {
203→    const sessionId = request.params.sessionId;
204→    const result = await deps.abortSession(sessionId);
205→
206→    if (!result.ok) {
207→      return sessionErrorResponse(result.error);
208→    }
209→
210→    return abortResponse();
211→  };
212→
213→  const review: RouteHandler = async (request) => {
214→    const sessionId = request.params.sessionId;
215→    const result = await deps.getReview(sessionId);
216→
217→    if (!result.ok) {
218→      return sessionErrorResponse(result.error);
219→    }
220→
221→    return reviewResponse(result.value);
222→  };
223→
224→  const reject: RouteHandler = async (request) => {
225→    const sessionId = request.params.sessionId;
226→    const body = await parseJsonBody<RejectBody>(request);
227→
228→    if (!body?.feedback || body.feedback.trim() === "") {
229→      return jsonError("feedback is required", 400);
230→    }
231→
232→    const result = await deps.rejectSession(sessionId, body.feedback);
233→
234→    if (!result.ok) {
235→      return sessionErrorResponse(result.error);
236→    }
237→
238→    return rejectResponse();
239→  };
240→
241→  const prompt: RouteHandler = async (request) => {
242→    const sessionId = request.params.sessionId;
243→    const body = await parseJsonBody<PromptBody>(request);
244→
245→    if (!body?.text || body.text.trim() === "") {
246→      return jsonError("text is required", 400);
247→    }
248→
249→    const result = await deps.sendPrompt(sessionId, body.text);
250→
251→    if (!result.ok) {
252→      return sessionErrorResponse(result.error);
253→    }
254→
255→    return promptResponse();
256→  };
257→
258→  return { assign, status, accept, abort, review, reject, prompt };
259→}
260→
261→// ---------------------------------------------------------------------------
262→// SSE stream route handler factory
263→// ---------------------------------------------------------------------------
264→
265→export type StreamRouteDeps = {
266→  sseRegistry: SseRegistry;
267→};
268→
269→export function createStreamRouteHandler(deps: StreamRouteDeps) {
270→  const stream: RouteHandler = async (request) => {
271→    const sessionId = request.params.sessionId;
272→
273→    if (!sessionId) {
274→      return jsonError("sessionId is required", 400);
275→    }
276→
277→    const streamId = `stream-${sessionId}`;
278→    return deps.sseRegistry.handleStreamRequest(streamId);
279→  };
280→
281→  return { stream };
282→}
283→
284→// ---------------------------------------------------------------------------
285→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
286→// ---------------------------------------------------------------------------
287→
288→export type OrchestratorWiringDeps = {
289→  surreal: import("surrealdb").Surreal;
290→  shellExec: import("./worktree-manager").ShellExec;
291→  brainBaseUrl: string;
292→  sseRegistry?: SseRegistry;
293→  queryFn: import("./spawn-agent").QueryFn;
294→};
295→
296→export function wireOrchestratorRoutes(
297→  wiringDeps: OrchestratorWiringDeps,
298→): {
299→  assign: RouteHandler;
300→  status: RouteHandler;
301→  accept: RouteHandler;
302→  abort: RouteHandler;
303→  review: RouteHandler;
304→  reject: RouteHandler;
305→  prompt: RouteHandler;
306→  stream?: RouteHandler;
307→} {
308→  // Lazy imports to keep module boundary clean
309→  const lifecycleImport = import("./session-lifecycle");
310→  const queriesImport = import("../mcp/mcp-queries");
311→  const guardImport = import("./assignment-guard");
312→  const stallDetectorImport = import("./stall-detector");
313→
314→  // Helper: resolve repo_path from workspace record
315→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
316→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
317→      `SELECT repo_path FROM $ws;`,
318→      { ws: workspaceRecord },
319→    );
320→    const repoPath = rows[0]?.repo_path;
321→    if (!repoPath) {
322→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
323→    }
324→    return repoPath;
325→  };
326→
327→  // Use mock spawn for acceptance tests, production spawn otherwise
328→  const spawnAgentImport = process.env.ORCHESTRATOR_MOCK_AGENT === "true"
329→    ? Promise.resolve({
330→        createSpawnAgent: (_qfn: import("./spawn-agent").QueryFn): import("./spawn-agent").SpawnAgentFn =>
331→          () => ({
332→            messages: (async function* () {})(),
333→            abort: () => {},
334→          }),
335→      })
336→    : import("./spawn-agent");
337→
338→  const routeDeps: OrchestratorRouteDeps = {
339→    createSession: async (workspaceId, taskId, authToken) => {
340→      const [lifecycle, queries, guard, { createSpawnAgent }, stallDetector] = await Promise.all([
341→        lifecycleImport,
342→        queriesImport,
343→        guardImport,
344→        spawnAgentImport,
345→        stallDetectorImport,
346→      ]);
347→      const spawnAgent = createSpawnAgent(wiringDeps.queryFn);
348→      const result = await lifecycle.createOrchestratorSession({
349→        surreal: wiringDeps.surreal,
350→        shellExec: wiringDeps.shellExec,
351→        brainBaseUrl: wiringDeps.brainBaseUrl,
352→        workspaceId,
353→        taskId,
354→        authToken,
355→        validateAssignment: guard.validateAssignment,
356→        createAgentSession: queries.createAgentSession,
357→        spawnAgent,
358→      });
359→
360→      // Wire SSE stream + event iteration on success
361→      if (result.ok && wiringDeps.sseRegistry) {
362→        const { agentSessionId, streamId } = result.value;
363→        wiringDeps.sseRegistry.registerMessage(streamId);
364→
365→        const handle = lifecycle.getHandle(agentSessionId);
366→        if (handle) {
367→          const { RecordId } = await import("surrealdb");
368→          lifecycle.startEventIteration(
369→            {
370→              emitEvent: wiringDeps.sseRegistry.emitEvent,
371→              updateSessionStatus: async (sid, status, error) => {
372→                const rec = new RecordId("agent_session", sid);
373→                await wiringDeps.surreal.update(rec).merge({
374→                  orchestrator_status: status,
375→                  ...(error !== undefined ? { error } : {}),
376→                });
377→              },
378→              updateLastEventAt: async (sid) => {
379→                const rec = new RecordId("agent_session", sid);
380→                await wiringDeps.surreal.update(rec).merge({
381→                  last_event_at: new Date(),
382→                });
383→              },
384→              getSessionStatus: async (sid) => {
385→                const rec = new RecordId("agent_session", sid);
386→                const row = await wiringDeps.surreal.select(rec) as { orchestrator_status?: string } | undefined;
387→                return (row?.orchestrator_status ?? "error") as import("./types").OrchestratorStatus;
388→              },
389→              startStallDetector: (sid, stId) =>
390→                stallDetector.startStallDetector(
391→                  {
392→                    abortSession: async (abortSid) => {
393→                      const abortResult = await lifecycle.abortOrchestratorSession({
394→                        surreal: wiringDeps.surreal,
395→                        shellExec: wiringDeps.shellExec,
396→                        resolveRepoRoot,
397→                        sessionId: abortSid,
398→                        endAgentSession: queries.endAgentSession,
399→                      });
400→                      return abortResult;
401→                    },
402→                    createObservation: async () => {},
403→                    emitEvent: wiringDeps.sseRegistry!.emitEvent,
404→                  },
405→                  stallDetector.DEFAULT_STALL_CONFIG,
406→                  sid,
407→                  stId,
408→                ),
409→            },
410→            handle.messages,
411→            streamId,
412→            agentSessionId,
413→          );
414→        }
415→      }
416→
417→      return result;
418→    },
419→
420→    getSessionStatus: async (sessionId) => {
421→      const lifecycle = await lifecycleImport;
422→      return lifecycle.getOrchestratorSessionStatus({
423→        surreal: wiringDeps.surreal,
424→        sessionId,
425→      });
426→    },
427→
428→    abortSession: async (sessionId) => {
429→      const [lifecycle, queries] = await Promise.all([
430→        lifecycleImport,
431→        queriesImport,
432→      ]);
433→      return lifecycle.abortOrchestratorSession({
434→        surreal: wiringDeps.surreal,
435→        shellExec: wiringDeps.shellExec,
436→        resolveRepoRoot,
437→        sessionId,
438→        endAgentSession: queries.endAgentSession,
439→      });
440→    },
441→
442→    acceptSession: async (sessionId, summary) => {
443→      const [lifecycle, queries] = await Promise.all([
444→        lifecycleImport,
445→        queriesImport,
446→      ]);
447→      return lifecycle.acceptOrchestratorSession({
448→        surreal: wiringDeps.surreal,
449→        sessionId,
450→        summary,
451→        endAgentSession: queries.endAgentSession,
452→      });
453→    },
454→
455→    getReview: async (sessionId) => {
456→      const [lifecycle, worktreeManager] = await Promise.all([
457→        lifecycleImport,
458→        import("./worktree-manager"),
459→      ]);
460→      return lifecycle.getOrchestratorReview({
461→        surreal: wiringDeps.surreal,
462→        sessionId,
463→        resolveRepoRoot,
464→        getDiff: (repoRoot: string, branchName: string) =>
465→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
466→        getTaskTitle: async (taskId: string) => {
467→          const { RecordId } = await import("surrealdb");
468→          const taskRecord = new RecordId("task", taskId);
469→          const rows = (await wiringDeps.surreal.query(
470→            `SELECT title FROM $task;`,
471→            { task: taskRecord },
472→          )) as Array<Array<{ title: string }>>;
473→          return rows[0]?.[0]?.title ?? "";
474→        },
475→      });
476→    },
477→
478→    rejectSession: async (sessionId, feedback) => {
479→      const lifecycle = await lifecycleImport;
480→      return lifecycle.rejectOrchestratorSession({
481→        surreal: wiringDeps.surreal,
482→        sessionId,
483→        feedback,
484→      });
485→    },
486→
487→    sendPrompt: async (sessionId, text) => {
488→      const lifecycle = await lifecycleImport;
489→      return lifecycle.sendSessionPrompt({
490→        surreal: wiringDeps.surreal,
491→        sessionId,
492→        text,
493→      });
494→    },
495→  };
496→
497→  const handlers = createOrchestratorRouteHandlers(routeDeps);
498→
499→  const streamHandler = wiringDeps.sseRegistry
500→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
501→    : undefined;
502→
503→  return {
504→    assign: withRequestLogging("orchestrator.assign", "POST", handlers.assign),
505→    status: withRequestLogging("orchestrator.status", "GET", handlers.status),
506→    accept: withRequestLogging("orchestrator.accept", "POST", handlers.accept),
507→    abort: withRequestLogging("orchestrator.abort", "POST", handlers.abort),
508→    review: withRequestLogging("orchestrator.review", "GET", handlers.review),
509→    reject: withRequestLogging("orchestrator.reject", "POST", handlers.reject),
510→    prompt: withRequestLogging("orchestrator.prompt", "POST", handlers.prompt),
511→    ...(streamHandler
512→      ? { stream: withRequestLogging("orchestrator.stream", "GET", streamHandler.stream) }
513→      : {}),
514→  };
515→}
516→

 1→// ---------------------------------------------------------------------------
 2→// Agent spawning — SDK adapter over @anthropic-ai/claude-agent-sdk
 3→// ---------------------------------------------------------------------------
 4→
 5→import { buildAgentOptions, type AgentSpawnConfig } from "./agent-options";
 6→import type { query as sdkQuery } from "@anthropic-ai/claude-agent-sdk";
 7→
 8→// ---------------------------------------------------------------------------
 9→// QueryFn — port type matching the SDK's query() signature
10→// ---------------------------------------------------------------------------
11→
12→export type QueryFn = typeof sdkQuery;
13→
14→// ---------------------------------------------------------------------------
15→// AgentHandle — returned by spawnAgent
16→// ---------------------------------------------------------------------------
17→
18→export type AgentHandle = {
19→  messages: AsyncIterable<unknown>;
20→  abort: () => void;
21→};
22→
23→// ---------------------------------------------------------------------------
24→// SpawnAgentFn — port signature for agent spawning
25→// ---------------------------------------------------------------------------
26→
27→export type SpawnAgentFn = (config: AgentSpawnConfig) => AgentHandle;
28→
29→// ---------------------------------------------------------------------------
30→// createSpawnAgent — factory that injects the query function dependency
31→// ---------------------------------------------------------------------------
32→
33→export function createSpawnAgent(queryFn: QueryFn): SpawnAgentFn {
34→  return (config: AgentSpawnConfig): AgentHandle => {
35→    const abortController = new AbortController();
36→    const opts = buildAgentOptions(config, abortController);
37→
38→    const stream = queryFn(opts);
39→
40→    return {
41→      messages: stream,
42→      abort: () => abortController.abort(),
43→    };
44→  };
45→}
46→

  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { AgentHandle, SpawnAgentFn } from "./spawn-agent";
  3→import type { AgentSpawnConfig } from "./agent-options";
  4→import type { ShellExec } from "./worktree-manager";
  5→import { createWorktree, removeWorktree } from "./worktree-manager";
  6→import type { AssignmentResult } from "./assignment-guard";
  7→import type { AssignmentError, OrchestratorStatus, TerminalOrchestratorStatus } from "./types";
  8→import { TERMINAL_ORCHESTRATOR_STATUSES } from "./types";
  9→import { startEventBridge, type SdkMessage } from "./event-bridge";
 10→import type { StreamEvent } from "../../shared/contracts";
 11→import type { StallDetectorHandle } from "./stall-detector";
 12→
 13→// ---------------------------------------------------------------------------
 14→// Types — exported for tests
 15→// ---------------------------------------------------------------------------
 16→
 17→export type SessionDeps = {
 18→  surreal: Surreal;
 19→  shellExec: ShellExec;
 20→  brainBaseUrl: string;
 21→  spawnAgent?: SpawnAgentFn;
 22→};
 23→
 24→export type SessionErrorCode =
 25→  | "TASK_NOT_FOUND"
 26→  | "TASK_NOT_ASSIGNABLE"
 27→  | "AGENT_ALREADY_ACTIVE"
 28→  | "WORKSPACE_MISMATCH"
 29→  | "MISSING_TASK_ID"
 30→  | "WORKTREE_ERROR"
 31→  | "SESSION_NOT_FOUND"
 32→  | "SESSION_ERROR";
 33→
 34→export type SessionError = {
 35→  code: SessionErrorCode;
 36→  message: string;
 37→  httpStatus: number;
 38→};
 39→
 40→export type SessionResult<T> =
 41→  | { ok: true; value: T }
 42→  | { ok: false; error: SessionError };
 43→
 44→export type OrchestratorSessionResult = SessionResult<{
 45→  agentSessionId: string;
 46→  streamId: string;
 47→  worktreeBranch: string;
 48→}>;
 49→
 50→export type SessionStatusResult = SessionResult<{
 51→  orchestratorStatus: OrchestratorStatus;
 52→  worktreeBranch?: string;
 53→  worktreePath?: string;
 54→  lastEventAt?: string;
 55→  startedAt?: string;
 56→  error?: string;
 57→}>;
 58→
 59→export type AbortSessionResult = SessionResult<{
 60→  aborted: boolean;
 61→  sessionId: string;
 62→}>;
 63→
 64→export type AcceptSessionResult = SessionResult<{
 65→  accepted: boolean;
 66→  sessionId: string;
 67→}>;
 68→
 69→export type ReviewResult = SessionResult<{
 70→  taskTitle: string;
 71→  diff: import("./worktree-manager").DiffResult;
 72→  session: {
 73→    orchestratorStatus: string;
 74→    worktreeBranch?: string;
 75→    startedAt?: string;
 76→    lastEventAt?: string;
 77→    toolCallCount?: number;
 78→    filesEdited?: number;
 79→  };
 80→}>;
 81→
 82→export type RejectSessionResult = SessionResult<{
 83→  rejected: boolean;
 84→  continuing: boolean;
 85→}>;
 86→
 87→export type PromptSessionResult = SessionResult<{
 88→  delivered: boolean;
 89→}>;
 90→
 91→// ---------------------------------------------------------------------------
 92→// In-memory handle registry — maps agentSessionId to AgentHandle
 93→// ---------------------------------------------------------------------------
 94→
 95→const handleRegistry = new Map<string, AgentHandle>();
 96→
 97→// Exported for testing cleanup
 98→export function clearHandleRegistry(): void {
 99→  handleRegistry.clear();
100→}
101→
102→export function getHandle(sessionId: string): AgentHandle | undefined {
103→  return handleRegistry.get(sessionId);
104→}
105→
106→// ---------------------------------------------------------------------------
107→// Event iteration — port (dependencies as function signatures)
108→// ---------------------------------------------------------------------------
109→
110→export type EventIterationDeps = {
111→  emitEvent: (streamId: string, event: StreamEvent) => void;
112→  updateSessionStatus: (
113→    sessionId: string,
114→    status: OrchestratorStatus,
115→    error?: string,
116→  ) => Promise<void>;
117→  updateLastEventAt: (sessionId: string) => Promise<void>;
118→  getSessionStatus: (sessionId: string) => Promise<OrchestratorStatus>;
119→  startStallDetector: (sessionId: string, streamId: string) => StallDetectorHandle;
120→};
121→
122→const TERMINAL_STATUSES: ReadonlySet<string> = new Set<string>(
123→  TERMINAL_ORCHESTRATOR_STATUSES,
124→);
125→
126→/**
127→ * Iterates the SDK message stream, forwarding messages through the event
128→ * bridge. Transitions session to "active" on first message, starts stall
129→ * detection, and stops on terminal status or error.
130→ *
131→ * Returns a Promise that resolves when iteration ends (for testing).
132→ * In production, this is launched fire-and-forget.
133→ */
134→export function startEventIteration(
135→  deps: EventIterationDeps,
136→  messageStream: AsyncIterable<unknown>,
137→  streamId: string,
138→  sessionId: string,
139→): Promise<void> {
140→  const stallDetector = deps.startStallDetector(sessionId, streamId);
141→
142→  const bridge = startEventBridge(
143→    {
144→      emitEvent: deps.emitEvent,
145→      updateLastEventAt: deps.updateLastEventAt,
146→    },
147→    streamId,
148→    sessionId,
149→    stallDetector,
150→  );
151→
152→  let firstMessageReceived = false;
153→
154→  async function iterate(): Promise<void> {
155→    try {
156→      for await (const rawMessage of messageStream) {
157→        // Check if session has reached terminal status
158→        const currentStatus = await deps.getSessionStatus(sessionId);
159→        if (TERMINAL_STATUSES.has(currentStatus)) {
160→          break;
161→        }
162→
163→        // Transition to active on first message
164→        if (!firstMessageReceived) {
165→          firstMessageReceived = true;
166→          await deps.updateSessionStatus(sessionId, "active");
167→        }
168→
169→        // Forward through event bridge (transform + emit + stall detection)
170→        bridge.handleMessage(rawMessage as SdkMessage);
171→      }
172→    } catch (err) {
173→      const errorMessage = err instanceof Error ? err.message : String(err);
174→      await deps.updateSessionStatus(sessionId, "error", errorMessage);
175→    } finally {
176→      bridge.stop();
177→      handleRegistry.delete(sessionId);
178→    }
179→  }
180→
181→  return iterate();
182→}
