432→// ---------------------------------------------------------------------------
433→// abortOrchestratorSession
434→// ---------------------------------------------------------------------------
435→
436→type AbortSessionInput = {
437→  surreal: Surreal;
438→  shellExec: ShellExec;
439→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
440→  sessionId: string;
441→  endAgentSession: (input: {
442→    surreal: Surreal;
443→    workspaceRecord: RecordId<"workspace", string>;
444→    sessionId: string;
445→    summary: string;
446→  }) => Promise<{ session_id: string; ended: boolean }>;
447→};
448→
449→export async function abortOrchestratorSession(
450→  input: AbortSessionInput,
451→): Promise<AbortSessionResult> {
452→  const lookup = await lookupSession(input.surreal, input.sessionId);
453→  if (!lookup.ok) {
454→    return { ok: false, error: lookup.error };
455→  }
456→  const { session, record: sessionRecord } = lookup;
457→
458→  // 1. Abort the agent process if handle exists
459→  const handle = handleRegistry.get(input.sessionId);
460→  if (handle) {
461→    handle.abort();
462→    handleRegistry.delete(input.sessionId);
463→  }
464→
465→  // 2. Update orchestrator_status to aborted
466→  await input.surreal.update(sessionRecord).merge({
467→    orchestrator_status: "aborted" as OrchestratorStatus,
468→  });
469→
470→  const workspaceRecord = requireWorkspace(session, input.sessionId);
471→
472→  // 3. Remove worktree if branch name exists
473→  if (session.worktree_branch) {
474→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
475→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
476→  }
477→
478→  // 4. Return task to ready
479→  if (session.task_id) {
480→    await input.surreal.update(session.task_id).merge({
481→      status: "ready",
482→      updated_at: new Date(),
483→    });
484→  }
485→
486→  // 5. End the agent session
487→  await input.endAgentSession({
488→    surreal: input.surreal,
489→    workspaceRecord,
490→    sessionId: input.sessionId,
491→    summary: "Session aborted",
492→  });
493→
494→  return {
495→    ok: true,
496→    value: {
497→      aborted: true,
498→      sessionId: input.sessionId,
499→    },
500→  };
501→}
502→
503→// ---------------------------------------------------------------------------
504→// acceptOrchestratorSession
505→// ---------------------------------------------------------------------------
506→
507→type AcceptSessionInput = {
508→  surreal: Surreal;
509→  sessionId: string;
510→  summary: string;
511→  endAgentSession: (input: {
512→    surreal: Surreal;
513→    workspaceRecord: RecordId<"workspace", string>;
514→    sessionId: string;
515→    summary: string;
516→  }) => Promise<{ session_id: string; ended: boolean }>;
517→};
518→
519→export async function acceptOrchestratorSession(
520→  input: AcceptSessionInput,
521→): Promise<AcceptSessionResult> {
522→  const lookup = await lookupSession(input.surreal, input.sessionId);
523→  if (!lookup.ok) {
524→    return { ok: false, error: lookup.error };
525→  }
526→  const { session, record: sessionRecord, status } = lookup;
527→
528→  if (!ACCEPTABLE_STATUSES.has(status)) {
529→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
530→  }
531→
532→  const workspaceRecord = requireWorkspace(session, input.sessionId);
533→
534→  // 1. Update orchestrator_status to completed
535→  await input.surreal.update(sessionRecord).merge({
536→    orchestrator_status: "completed" as OrchestratorStatus,
537→  });
538→
539→  // 2. Mark task as done
540→  if (session.task_id) {
541→    await input.surreal.update(session.task_id).merge({
542→      status: "done",
543→      updated_at: new Date(),
544→    });
545→  }
546→
547→  // 3. Clean up handle registry
548→  handleRegistry.delete(input.sessionId);
549→
550→  // 4. End the agent session
551→  await input.endAgentSession({
552→    surreal: input.surreal,
553→    workspaceRecord,
554→    sessionId: input.sessionId,
555→    summary: input.summary,
556→  });
557→
558→  return {
559→    ok: true,
560→    value: {
561→      accepted: true,
562→      sessionId: input.sessionId,
563→    },
564→  };
565→}
