567→// ---------------------------------------------------------------------------
568→// State guard helpers
569→// ---------------------------------------------------------------------------
570→
571→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
572→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
573→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
574→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
575→
576→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
577→  return {
578→    code: "SESSION_ERROR",
579→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
580→    httpStatus: 409,
581→  };
582→}
583→
584→function sessionAborted(sessionId: string): SessionError {
585→  return {
586→    code: "SESSION_ERROR",
587→    message: `Session ${sessionId} has been aborted`,
588→    httpStatus: 409,
589→  };
590→}
591→
592→// ---------------------------------------------------------------------------
593→// getOrchestratorReview
594→// ---------------------------------------------------------------------------
595→
596→type GetReviewInput = {
597→  surreal: Surreal;
598→  sessionId: string;
599→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
600→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
601→  getTaskTitle: (taskId: string) => Promise<string>;
602→};
603→
604→export async function getOrchestratorReview(
605→  input: GetReviewInput,
606→): Promise<ReviewResult> {
607→  const lookup = await lookupSession(input.surreal, input.sessionId);
608→  if (!lookup.ok) {
609→    return { ok: false, error: lookup.error };
610→  }
611→  const { session, status } = lookup;
612→
613→  if (status === "aborted") {
614→    return { ok: false, error: sessionAborted(input.sessionId) };
615→  }
616→
617→  if (!REVIEWABLE_STATUSES.has(status)) {
618→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
619→  }
620→
621→  // Get diff from the branch
622→  const branchName = session.worktree_branch ?? "";
623→  const workspaceRecord = requireWorkspace(session, input.sessionId);
624→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
625→  const diffResult = await input.getDiff(repoRoot, branchName);
626→
627→  const diff = diffResult.ok
628→    ? diffResult.value
629→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
630→
631→  // Get task title
632→  const taskId = session.task_id ? session.task_id.id : "";
633→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
634→
635→  return {
636→    ok: true,
637→    value: {
638→      taskTitle,
639→      diff,
640→      session: {
641→        orchestratorStatus: status,
642→        ...pickDefined({
643→          worktreeBranch: session.worktree_branch,
644→          startedAt: session.started_at,
645→          lastEventAt: session.last_event_at,
646→        }),
647→      },
648→    },
649→  };
650→}
