652→// ---------------------------------------------------------------------------
653→// rejectOrchestratorSession
654→// ---------------------------------------------------------------------------
655→
656→type RejectSessionInput = {
657→  surreal: Surreal;
658→  sessionId: string;
659→  feedback: string;
660→};
661→
662→export async function rejectOrchestratorSession(
663→  input: RejectSessionInput,
664→): Promise<RejectSessionResult> {
665→  const lookup = await lookupSession(input.surreal, input.sessionId);
666→  if (!lookup.ok) {
667→    return { ok: false, error: lookup.error };
668→  }
669→  const { session, record: sessionRecord, status } = lookup;
670→
671→  if (!REJECTABLE_STATUSES.has(status)) {
672→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
673→  }
674→
675→  // 1. Update session status to active (agent resumes work)
676→  await input.surreal.update(sessionRecord).merge({
677→    orchestrator_status: "active" as OrchestratorStatus,
678→    last_feedback: input.feedback,
679→  });
680→
681→  // 2. Return task to in_progress
682→  if (session.task_id) {
683→    await input.surreal.update(session.task_id).merge({
684→      status: "in_progress",
685→      updated_at: new Date(),
686→    });
687→  }
688→
689→  return {
690→    ok: true,
691→    value: {
692→      rejected: true,
693→      continuing: true,
694→    },
695→  };
696→}
