698→// ---------------------------------------------------------------------------
699→// sendSessionPrompt
700→// ---------------------------------------------------------------------------
701→
702→type SendPromptInput = {
703→  surreal: Surreal;
704→  sessionId: string;
705→  text: string;
706→};
707→
708→export async function sendSessionPrompt(
709→  input: SendPromptInput,
710→): Promise<PromptSessionResult> {
711→  const lookup = await lookupSession(input.surreal, input.sessionId);
712→  if (!lookup.ok) {
713→    return { ok: false, error: lookup.error };
714→  }
715→  const { status } = lookup;
716→
717→  if (!PROMPTABLE_STATUSES.has(status)) {
718→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
719→  }
720→
721→  // The Claude Agent SDK uses a single query() call per conversation.
722→  // Follow-up prompts are not supported in this model.
723→  return {
724→    ok: false,
725→    error: {
726→      code: "SESSION_ERROR",
727→      message: `Follow-up prompts are not supported with the Agent SDK. Session ${input.sessionId} runs a single query() conversation.`,
728→      httpStatus: 409,
729→    },
730→  };
731→}
