  1→/**
  2→ * Event bridge: transforms Claude Agent SDK messages into Brain StreamEvent
  3→ * variants and forwards them to the SSE registry.
  4→ *
  5→ * Pure transform function (transformSdkMessage) + effectful bridge handle
  6→ * (startEventBridge) that manages the event forwarding lifecycle.
  7→ */
  8→import type {
  9→  AgentTokenEvent,
 10→  AgentFileChangeEvent,
 11→  AgentStatusEvent,
 12→  StreamEvent,
 13→} from "../../shared/contracts";
 14→import { logWarn } from "../http/observability";
 15→import type { StallDetectorHandle } from "./stall-detector";
 16→
 17→// ---------------------------------------------------------------------------
 18→// SDK message types (from @anthropic-ai/claude-code)
 19→// ---------------------------------------------------------------------------
 20→
 21→export type ContentBlock =
 22→  | { type: "text"; text: string }
 23→  | { type: "tool_use"; id: string; name: string; input: Record<string, unknown> }
 24→  | { type: "tool_result"; tool_use_id: string; content: string };
 25→
 26→export type SdkMessage =
 27→  | { type: "assistant"; content: ContentBlock[] }
 28→  | { type: "result"; subtype: "success"; duration_ms: number }
 29→  | { type: "result"; subtype: "error"; error: string }
 30→  | { type: "user" };
 31→
 32→// ---------------------------------------------------------------------------
 33→// Port: dependencies as function signatures
 34→// ---------------------------------------------------------------------------
 35→
 36→export type EventBridgeDeps = {
 37→  emitEvent: (streamId: string, event: StreamEvent) => void;
 38→  updateLastEventAt: (sessionId: string) => Promise<void>;
 39→};
 40→
 41→// ---------------------------------------------------------------------------
 42→// Bridge handle
 43→// ---------------------------------------------------------------------------
 44→
 45→export type EventBridgeHandle = {
 46→  handleMessage: (message: SdkMessage) => void;
 47→  stop: () => void;
 48→};
 49→
 50→// ---------------------------------------------------------------------------
 51→// File operation tool detection
 52→// ---------------------------------------------------------------------------
 53→
 54→/** Tool names that represent file write/edit operations. */
 55→const FILE_WRITE_TOOLS = new Set(["Write"]);
 56→const FILE_EDIT_TOOLS = new Set(["Edit"]);
 57→
 58→function isFileOperationTool(toolName: string): boolean {
 59→  return FILE_WRITE_TOOLS.has(toolName) || FILE_EDIT_TOOLS.has(toolName);
 60→}
 61→
 62→function extractFileChangeType(toolName: string): AgentFileChangeEvent["changeType"] {
 63→  if (FILE_WRITE_TOOLS.has(toolName)) return "created";
 64→  if (FILE_EDIT_TOOLS.has(toolName)) return "modified";
 65→  return "modified";
 66→}
 67→
 68→function extractFilePath(input: Record<string, unknown>): string | undefined {
 69→  if (typeof input.file_path === "string") return input.file_path;
 70→  return undefined;
 71→}
 72→
 73→// ---------------------------------------------------------------------------
 74→// Pure transform: SDK message -> Brain StreamEvent[]
 75→// ---------------------------------------------------------------------------
 76→
 77→function transformTextBlock(
 78→  block: { type: "text"; text: string },
 79→  sessionId: string,
 80→): AgentTokenEvent {
 81→  return {
 82→    type: "agent_token",
 83→    sessionId,
 84→    token: block.text,
 85→  };
 86→}
 87→
 88→function transformToolUseBlock(
 89→  block: { type: "tool_use"; id: string; name: string; input: Record<string, unknown> },
 90→  sessionId: string,
 91→): AgentFileChangeEvent | undefined {
 92→  if (!isFileOperationTool(block.name)) return undefined;
 93→
 94→  const filePath = extractFilePath(block.input);
 95→  if (!filePath) return undefined;
 96→
 97→  return {
 98→    type: "agent_file_change",
 99→    sessionId,
100→    file: filePath,
101→    changeType: extractFileChangeType(block.name),
102→  };
103→}
104→
105→function transformAssistantContent(
106→  content: ContentBlock[],
107→  sessionId: string,
108→): StreamEvent[] {
109→  const events: StreamEvent[] = [];
110→  for (const block of content) {
111→    if (block.type === "text") {
112→      events.push(transformTextBlock(block, sessionId));
113→    } else if (block.type === "tool_use") {
114→      const fileEvent = transformToolUseBlock(block, sessionId);
115→      if (fileEvent) events.push(fileEvent);
116→    }
117→  }
118→  return events;
119→}
120→
121→function transformResultMessage(
122→  message: { type: "result"; subtype: "success"; duration_ms: number } | { type: "result"; subtype: "error"; error: string },
123→  sessionId: string,
124→): AgentStatusEvent {
125→  if (message.subtype === "error") {
126→    return {
127→      type: "agent_status",
128→      sessionId,
129→      status: "error",
130→      error: message.error,
131→    };
132→  }
133→  return {
134→    type: "agent_status",
135→    sessionId,
136→    status: "completed",
137→  };
138→}
139→
140→export function transformSdkMessage(
141→  message: SdkMessage,
142→  sessionId: string,
143→): StreamEvent[] {
144→  switch (message.type) {
145→    case "assistant":
146→      return transformAssistantContent(message.content, sessionId);
147→
148→    case "result":
149→      return [transformResultMessage(message, sessionId)];
150→
151→    default:
152→      return [];
153→  }
154→}
155→
156→// ---------------------------------------------------------------------------
157→// Step event detection for stall detector
158→// ---------------------------------------------------------------------------
159→
160→/** Returns true if the message contains tool_use blocks for file operations. */
161→function containsFileOperationStep(message: SdkMessage): boolean {
162→  if (message.type !== "assistant") return false;
163→  return message.content.some(
164→    (block) => block.type === "tool_use" && isFileOperationTool(block.name),
165→  );
166→}
167→
168→// ---------------------------------------------------------------------------
169→// Bridge handle factory
170→// ---------------------------------------------------------------------------
171→
172→export function startEventBridge(
173→  deps: EventBridgeDeps,
174→  streamId: string,
175→  sessionId: string,
176→  stallDetector?: StallDetectorHandle,
177→): EventBridgeHandle {
178→  let stopped = false;
179→
180→  const handleMessage = (message: SdkMessage): void => {
181→    if (stopped) return;
182→
183→    const streamEvents = transformSdkMessage(message, sessionId);
184→    for (const streamEvent of streamEvents) {
185→      deps.emitEvent(streamId, streamEvent);
186→    }
187→
188→    // Fire-and-forget: update last_event_at for stall detection
189→    if (streamEvents.length > 0) {
190→      deps.updateLastEventAt(sessionId).catch((err) => {
191→        logWarn("event-bridge", "Failed to update last_event_at", { sessionId, error: String(err) });
192→      });
193→    }
194→
195→    // Notify stall detector of activity
196→    if (stallDetector && streamEvents.length > 0) {
197→      stallDetector.recordActivity();
198→
199→      if (containsFileOperationStep(message)) {
200→        stallDetector.incrementStepCount();
201→      }
202→    }
203→  };
204→
205→  return {
206→    handleMessage,
207→    stop(): void {
208→      stopped = true;
209→      stallDetector?.stop();
210→    },
211→  };
212→}
213→

  1→/**
  2→ * Stall detector: monitors agent session activity and step counts.
  3→ *
  4→ * Pure check functions (checkStallTimeout, checkStepLimit) + effectful handle
  5→ * (startStallDetector) that manages timers and triggers abort/observation.
  6→ *
  7→ * Timer and clock are injectable for testability.
  8→ */
  9→import type { StreamEvent, AgentStallWarningEvent } from "../../shared/contracts";
 10→import type { AbortSessionResult } from "./session-lifecycle";
 11→
 12→// ---------------------------------------------------------------------------
 13→// Configuration
 14→// ---------------------------------------------------------------------------
 15→
 16→export type StallDetectorConfig = {
 17→  stallTimeoutMs: number;     // default: 300_000 (5 minutes)
 18→  maxSteps: number;           // default: 100
 19→  checkIntervalMs: number;    // default: 30_000 (30 seconds)
 20→};
 21→
 22→export const DEFAULT_STALL_CONFIG: StallDetectorConfig = {
 23→  stallTimeoutMs: 300_000,
 24→  maxSteps: 100,
 25→  checkIntervalMs: 30_000,
 26→};
 27→
 28→// ---------------------------------------------------------------------------
 29→// Ports: dependencies as function signatures
 30→// ---------------------------------------------------------------------------
 31→
 32→export type ObservationInput = {
 33→  text: string;
 34→  severity: "info" | "warning" | "conflict";
 35→  category: string;
 36→  sourceAgent: string;
 37→};
 38→
 39→export type StallDetectorDeps = {
 40→  abortSession: (sessionId: string) => Promise<AbortSessionResult>;
 41→  createObservation: (input: ObservationInput) => Promise<void>;
 42→  emitEvent: (streamId: string, event: StreamEvent) => void;
 43→};
 44→
 45→// ---------------------------------------------------------------------------
 46→// Injectable clock/timer for testability
 47→// ---------------------------------------------------------------------------
 48→
 49→export type Clock = {
 50→  now: () => number;
 51→  setInterval: (callback: () => void, ms: number) => ReturnType<typeof globalThis.setInterval>;
 52→  clearInterval: (id: ReturnType<typeof globalThis.setInterval>) => void;
 53→};
 54→
 55→const SYSTEM_CLOCK: Clock = {
 56→  now: () => Date.now(),
 57→  setInterval: globalThis.setInterval.bind(globalThis),
 58→  clearInterval: globalThis.clearInterval.bind(globalThis),
 59→};
 60→
 61→// ---------------------------------------------------------------------------
 62→// Handle
 63→// ---------------------------------------------------------------------------
 64→
 65→export type StallDetectorHandle = {
 66→  recordActivity: () => void;
 67→  incrementStepCount: () => void;
 68→  stop: () => void;
 69→};
 70→
 71→// ---------------------------------------------------------------------------
 72→// Pure check: timeout
 73→// ---------------------------------------------------------------------------
 74→
 75→export type StallCheckInput = {
 76→  lastActivityAt: number;
 77→  nowMs: number;
 78→  stallTimeoutMs: number;
 79→};
 80→
 81→export type StallCheckResult = {
 82→  stalled: boolean;
 83→  stallDurationMs?: number;
 84→};
 85→
 86→export function checkStallTimeout(input: StallCheckInput): StallCheckResult {
 87→  const elapsed = input.nowMs - input.lastActivityAt;
 88→  if (elapsed > input.stallTimeoutMs) {
 89→    return { stalled: true, stallDurationMs: elapsed };
 90→  }
 91→  return { stalled: false };
 92→}
 93→
 94→// ---------------------------------------------------------------------------
 95→// Pure check: step limit
 96→// ---------------------------------------------------------------------------
 97→
 98→export type StepLimitResult = {
 99→  exceeded: boolean;
100→  currentSteps: number;
101→  maxSteps: number;
102→};
103→
104→export function checkStepLimit(currentSteps: number, maxSteps: number): StepLimitResult {
105→  return {
106→    exceeded: currentSteps > maxSteps,
107→    currentSteps,
108→    maxSteps,
109→  };
110→}
111→
112→// ---------------------------------------------------------------------------
113→// Effectful handle factory
114→// ---------------------------------------------------------------------------
115→
116→export function startStallDetector(
117→  deps: StallDetectorDeps,
118→  config: StallDetectorConfig,
119→  sessionId: string,
120→  streamId: string,
121→  clock: Clock = SYSTEM_CLOCK,
122→): StallDetectorHandle {
123→  let stopped = false;
124→  let aborted = false;
125→  let lastActivityAt = clock.now();
126→  let stepCount = 0;
127→
128→  async function handleStall(reason: string, observation: string): Promise<void> {
129→    if (aborted || stopped) return;
130→    aborted = true;
131→
132→    const stallWarning: AgentStallWarningEvent = {
133→      type: "agent_stall_warning",
134→      sessionId,
135→      lastEventAt: new Date(lastActivityAt).toISOString(),
136→      stallDurationSeconds: Math.round((clock.now() - lastActivityAt) / 1000),
137→    };
138→
139→    deps.emitEvent(streamId, stallWarning);
140→    await deps.abortSession(sessionId);
141→    await deps.createObservation({
142→      text: observation,
143→      severity: "warning",
144→      category: "stall_detection",
145→      sourceAgent: "orchestrator",
146→    });
147→  }
148→
149→  function checkTimeout(): void {
150→    if (stopped || aborted) return;
151→
152→    const result = checkStallTimeout({
153→      lastActivityAt,
154→      nowMs: clock.now(),
155→      stallTimeoutMs: config.stallTimeoutMs,
156→    });
157→
158→    if (result.stalled) {
159→      const durationSec = Math.round((result.stallDurationMs ?? 0) / 1000);
160→      handleStall(
161→        "timeout",
162→        `Agent session stalled: no activity for ${durationSec} seconds`,
163→      );
164→    }
165→  }
166→
167→  const intervalId = clock.setInterval(checkTimeout, config.checkIntervalMs);
168→
169→  return {
170→    recordActivity(): void {
171→      if (stopped) return;
172→      lastActivityAt = clock.now();
173→    },
174→
175→    incrementStepCount(): void {
176→      if (stopped || aborted) return;
177→      stepCount += 1;
178→
179→      const result = checkStepLimit(stepCount, config.maxSteps);
180→      if (result.exceeded) {
181→        handleStall(
182→          "step_limit",
183→          `Agent session exceeded maximum step count: ${stepCount}/${config.maxSteps} steps`,
184→        );
185→      }
186→    },
187→
188→    stop(): void {
189→      stopped = true;
190→      clock.clearInterval(intervalId);
191→    },
192→  };
193→}
