  1→import { RecordId, type Surreal } from "surrealdb";
  2→import {
  3→  ASSIGNABLE_TASK_STATUSES,
  4→  ACTIVE_ORCHESTRATOR_STATUSES,
  5→  type AssignableTaskStatus,
  6→  type AssignmentError,
  7→  type AssignmentValidation,
  8→  type TaskRow,
  9→  type ActiveSessionRow,
 10→} from "./types";
 11→
 12→// ---------------------------------------------------------------------------
 13→// Result type — discriminated union for success/failure
 14→// ---------------------------------------------------------------------------
 15→
 16→export type AssignmentResult =
 17→  | { ok: true; validation: AssignmentValidation }
 18→  | { ok: false; error: AssignmentError };
 19→
 20→// ---------------------------------------------------------------------------
 21→// Pure helpers
 22→// ---------------------------------------------------------------------------
 23→
 24→function isAssignableStatus(status: string): status is AssignableTaskStatus {
 25→  return (ASSIGNABLE_TASK_STATUSES as readonly string[]).includes(status);
 26→}
 27→
 28→function missingTaskId(): AssignmentResult {
 29→  return {
 30→    ok: false,
 31→    error: {
 32→      code: "MISSING_TASK_ID",
 33→      message: "taskId is required",
 34→      httpStatus: 400,
 35→    },
 36→  };
 37→}
 38→
 39→function taskNotFound(taskId: string): AssignmentResult {
 40→  return {
 41→    ok: false,
 42→    error: {
 43→      code: "TASK_NOT_FOUND",
 44→      message: `Task not found: ${taskId}`,
 45→      httpStatus: 404,
 46→    },
 47→  };
 48→}
 49→
 50→function workspaceMismatch(taskId: string): AssignmentResult {
 51→  return {
 52→    ok: false,
 53→    error: {
 54→      code: "WORKSPACE_MISMATCH",
 55→      message: `Task ${taskId} does not belong to the requested workspace`,
 56→      httpStatus: 403,
 57→    },
 58→  };
 59→}
 60→
 61→function taskNotAssignable(taskId: string, status: string): AssignmentResult {
 62→  return {
 63→    ok: false,
 64→    error: {
 65→      code: "TASK_NOT_ASSIGNABLE",
 66→      message: `Task ${taskId} has status '${status}' and cannot be assigned (must be ready or todo)`,
 67→      httpStatus: 409,
 68→    },
 69→  };
 70→}
 71→
 72→function agentAlreadyActive(taskId: string): AssignmentResult {
 73→  return {
 74→    ok: false,
 75→    error: {
 76→      code: "AGENT_ALREADY_ACTIVE",
 77→      message: `Task ${taskId} already has an active agent session`,
 78→      httpStatus: 409,
 79→    },
 80→  };
 81→}
 82→
 83→function repoPathRequired(workspaceId: string): AssignmentResult {
 84→  return {
 85→    ok: false,
 86→    error: {
 87→      code: "REPO_PATH_REQUIRED",
 88→      message: `Workspace ${workspaceId} has no repo_path configured. Set a repository path before assigning tasks to agents.`,
 89→      httpStatus: 400,
 90→    },
 91→  };
 92→}
 93→
 94→// ---------------------------------------------------------------------------
 95→// DB queries (thin wrappers — side effects isolated here)
 96→// ---------------------------------------------------------------------------
 97→
 98→async function fetchTask(
 99→  surreal: Surreal,
100→  taskRecord: RecordId<"task", string>,
101→): Promise<TaskRow | undefined> {
102→  const [rows] = await surreal.query<[TaskRow[]]>(
103→    `SELECT id, title, status, workspace FROM $taskRecord;`,
104→    { taskRecord },
105→  );
106→  return rows[0];
107→}
108→
109→type WorkspaceRepoRow = {
110→  repo_path?: string;
111→};
112→
113→async function fetchWorkspaceRepoPath(
114→  surreal: Surreal,
115→  workspaceRecord: RecordId<"workspace", string>,
116→): Promise<string | undefined> {
117→  const [rows] = await surreal.query<[WorkspaceRepoRow[]]>(
118→    `SELECT repo_path FROM $workspaceRecord;`,
119→    { workspaceRecord },
120→  );
121→  return rows[0]?.repo_path;
122→}
123→
124→async function hasActiveSession(
125→  surreal: Surreal,
126→  taskRecord: RecordId<"task", string>,
127→): Promise<boolean> {
128→  const [rows] = await surreal.query<[ActiveSessionRow[]]>(
129→    `SELECT id, orchestrator_status FROM agent_session
130→     WHERE task_id = $taskRecord
131→       AND orchestrator_status IN $activeStatuses
132→     LIMIT 1;`,
133→    { taskRecord, activeStatuses: [...ACTIVE_ORCHESTRATOR_STATUSES] },
134→  );
135→  return rows.length > 0;
136→}
137→
138→// ---------------------------------------------------------------------------
139→// Orchestration — pure pipeline over DB results
140→// ---------------------------------------------------------------------------
141→
142→/**
143→ * Validate that a task exists, is in an assignable status, belongs to the
144→ * given workspace, and has no active agent session already working on it.
145→ */
146→export async function validateAssignment(
147→  surreal: Surreal,
148→  workspaceId: string,
149→  taskId: string,
150→): Promise<AssignmentResult> {
151→  // 1. Input validation
152→  if (!taskId) {
153→    return missingTaskId();
154→  }
155→
156→  const taskRecord = new RecordId("task", taskId);
157→
158→  // 2. Task existence
159→  const task = await fetchTask(surreal, taskRecord);
160→  if (!task) {
161→    return taskNotFound(taskId);
162→  }
163→
164→  // 3. Workspace membership
165→  const taskWorkspaceId = task.workspace.id as string;
