 32→type SurrealSpy = {
 33→  stub: unknown;
 34→  queries: Array<{ sql: string; bindings?: Record<string, unknown> }>;
 35→  creates: Array<{ record: unknown; content: unknown }>;
 36→  updates: Array<{ record: unknown; merge: unknown }>;
