 40→function createSurrealSpy(responses: {
 41→  taskQuery?: QueryResult;
 42→  sessionQuery?: QueryResult;
 43→  sessionSelect?: Record<string, unknown>;
 44→  createReturn?: Record<string, unknown>;
 45→}): SurrealSpy {
 46→  const spy: SurrealSpy = {
 47→    stub: undefined,
 48→    queries: [],
 49→    creates: [],
 50→    updates: [],
 51→    selects: [],
 52→  };
 53→
 54→  spy.stub = {
 55→    query(sql: string, bindings?: Record<string, unknown>) {
 56→      spy.queries.push({ sql, bindings });
 57→
 58→      // Task lookup
 59→      if (sql.includes("FROM $taskRecord")) {
 60→        return Promise.resolve([responses.taskQuery ?? []]);
 61→      }
 62→      // Active session check
 63→      if (sql.includes("orchestrator_status") && sql.includes("agent_session")) {
 64→        return Promise.resolve([responses.sessionQuery ?? []]);
 65→      }
 66→      // Session orchestrator fields query (for getStatus)
 67→      if (sql.includes("orchestrator_status") && sql.includes("$sessionRecord")) {
 68→        return Promise.resolve([responses.sessionSelect ? [responses.sessionSelect] : []]);
 69→      }
 70→      // Update queries
 71→      if (sql.includes("UPDATE")) {
 72→        return Promise.resolve([responses.createReturn ?? {}]);
 73→      }
 74→      return Promise.resolve([[]]);
 75→    },
 76→    create(record: unknown) {
 77→      return {
 78→        content(content: unknown) {
 79→          spy.creates.push({ record, content });
 80→          return Promise.resolve(responses.createReturn ?? { id: record });
 81→        },
 82→      };
 83→    },
 84→    update(record: unknown) {
 85→      return {
 86→        merge(data: unknown) {
 87→          spy.updates.push({ record, merge: data });
 88→          return Promise.resolve({ id: record, ...data as object });
 89→        },
 90→      };
 91→    },
 92→    select(record: unknown) {
 93→      spy.selects.push({ record });
 94→      return Promise.resolve(responses.sessionSelect ?? undefined);
 95→    },
 96→    delete(_record: unknown) {
 97→      return Promise.resolve(undefined);
 98→    },
 99→  };
